     8→function getTransactionDescription(type: TransactionType): string {
     9→  return TYPE_LABELS[type] || '';
    10→}
    11→
    12→function matchesPeriodFilter(
    13→  transactionDate: Date,
    14→  periodStart: Date | null,
    15→  todayEnd: Date,
    16→): boolean {
    17→  if (!periodStart) return true;
    18→  return transactionDate >= periodStart && transactionDate <= todayEnd;
    19→}
    20→
    21→function matchesTypeFilter(
    22→  transactionType: string,
    23→  typesSet: Set<string> | null,
    24→): boolean {
    25→  if (!typesSet) return true;
    26→  return typesSet.has(transactionType.toUpperCase());
    27→}
    28→
    29→export function getFilteredTransactions(
    30→  transactions: PointsTransaction[],
    31→  filters?: AppliedFilters,
    32→): PointsTransaction[] {
    33→  if (
    34→    !filters ||
    35→    (!filters.period && (!filters.types || filters.types.length === 0))
    36→  ) {
    37→    return transactions;
    38→  }
    39→
    40→  const now = new Date();
    41→  const todayEnd = new Date(now);
    42→  todayEnd.setHours(23, 59, 59, 999);
    43→
    44→  const periodStart = filters.period
    45→    ? (() => {
    46→        const date = new Date(now);
    47→        date.setDate(date.getDate() - filters.period);
    48→        date.setHours(0, 0, 0, 0);
    49→        return date;
    50→      })()
    51→    : null;
    52→
    53→  const hasTypeFilter = filters.types && filters.types.length > 0;
    54→  const typesSet = hasTypeFilter
    55→    ? new Set(filters.types!.map(type => type.toUpperCase()))
    56→    : null;
    57→
    58→  return transactions.filter(transaction => {
    59→    const transactionDate = new Date(transaction.date);
    60→
    61→    if (!matchesPeriodFilter(transactionDate, periodStart, todayEnd)) {
    62→      return false;
    63→    }
    64→
    65→    if (!matchesTypeFilter(transaction.type, typesSet)) {
    66→      return false;
    67→    }
    68→
    69→    return true;
    70→  });
    71→}
    72→
    73→function matchesSearchText(
    74→  transaction: PointsTransaction,
    75→  normalizedSearch: string,
    76→  isExpiringTab: boolean,
    77→): boolean {
    78→  const amountStr = String(transaction.amount);
    79→
    80→  if (amountStr.includes(normalizedSearch)) {
    81→    return true;
    82→  }
    83→
    84→  if (isExpiringTab) {
    85→    return false;
    86→  }
    87→
    88→  const description = getTransactionDescription(transaction.type).toLowerCase();
    89→  if (description.includes(normalizedSearch)) {
    90→    return true;
    91→  }
    92→
    93→  if (transaction.description?.toLowerCase().includes(normalizedSearch)) {
    94→    return true;
    95→  }
    96→
    97→  return false;
    98→}
    99→
   100→export function getFilteredTransactionsByText(
   101→  transactions: PointsTransaction[],
   102→  searchText: string,
   103→  isExpiringTab = false,
   104→): PointsTransaction[] {
   105→  if (!searchText?.trim() || !transactions?.length) {
   106→    return transactions;
   107→  }
   108→
   109→  const normalizedSearch = searchText.toLowerCase().trim();
   110→
   111→  return transactions.filter(transaction =>
   112→    matchesSearchText(transaction, normalizedSearch, isExpiringTab));
   113→}
