     1→import { getPointsExtractApi, getPointsBalanceApi, type ExtractRequestDto } from '../api';
     2→import { getPointsExtractFromResponse, processPointsExtractData } from '../repository';
     3→import { useRootStore } from '../..';
     4→import {
     5→  PointsExtractStatus,
     6→  PointsBalanceStatus,
     7→  type PointsExtractData,
     8→} from '../models';
     9→import { eventServerResponse } from '~/constants/functions';
    10→import { EXTRACT_CONSTANTS, ANALYTICS_EVENTS } from '../constants';
    11→import { getParticipantIdFromToken } from '../utils';
    12→
    13→interface GetPointsExtractPayload {
    14→  page?: number;
    15→  type?: ExtractRequestDto['type'];
    16→  participantId?: string;
    17→}
    18→
    19→function shouldFetchExtract(
    20→  status: PointsExtractStatus,
    21→  isFirstPage: boolean,
    22→): boolean {
    23→  if (isFirstPage) {
    24→    return (
    25→      status !== PointsExtractStatus.LOADING &&
    26→      status !== PointsExtractStatus.SUCCESS
    27→    );
    28→  }
    29→  return true;
    30→}
    31→
    32→function handleExtractSuccess(
    33→  extractData: PointsExtractData,
    34→  processedData: ReturnType<typeof processPointsExtractData>,
    35→  isFirstPage: boolean,
    36→): void {
    37→  const { pointsExtractActions } = useRootStore.getState();
    38→
    39→  if (isFirstPage) {
    40→    pointsExtractActions.setExtractData(extractData, processedData);
    41→  } else {
    42→    pointsExtractActions.appendExtractData(extractData, processedData);
    43→  }
    44→
    45→  eventServerResponse(ANALYTICS_EVENTS.EXTRACT_SUCCESS);
    46→}
    47→
    48→function handleExtractError(isFirstPage: boolean): void {
    49→  const { pointsExtractActions } = useRootStore.getState();
    50→
    51→  if (isFirstPage) {
    52→    pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
    53→  } else {
    54→    pointsExtractActions.setLoadingMore(false);
    55→  }
    56→
    57→  eventServerResponse(ANALYTICS_EVENTS.EXTRACT_ERROR);
    58→}
    59→
    60→export async function getPointsExtract(
    61→  payload?: GetPointsExtractPayload,
    62→): Promise<void> {
    63→  const { pointsExtractActions, pointsExtract } = useRootStore.getState();
    64→
    65→  const page = payload?.page ?? EXTRACT_CONSTANTS.DEFAULT_PAGE;
    66→  const isFirstPage = page === EXTRACT_CONSTANTS.DEFAULT_PAGE;
    67→
    68→  if (!shouldFetchExtract(pointsExtract.status, isFirstPage)) {
    69→    return;
    70→  }
    71→
    72→  if (isFirstPage) {
    73→    pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
    74→  } else {
    75→    pointsExtractActions.setLoadingMore(true);
    76→  }
    77→
    78→  try {
    79→    const participantId =
    80→      payload?.participantId ?? (await getParticipantIdFromToken());
    81→
    82→    if (!participantId) {
    83→      handleExtractError(isFirstPage);
    84→      return;
    85→    }
    86→
    87→    const requestPayload: ExtractRequestDto = {
    88→      participantId,
    89→      page,
    90→      pageSize: EXTRACT_CONSTANTS.DEFAULT_PAGE_SIZE,
    91→      ...(payload?.type ? { type: payload.type } : {}),
    92→    };
    93→
    94→    const response = await getPointsExtractApi(requestPayload);
    95→    const extractData = getPointsExtractFromResponse(response);
    96→
    97→    if (extractData) {
    98→      const processedData = processPointsExtractData(extractData);
    99→      handleExtractSuccess(extractData, processedData, isFirstPage);
   100→      return;
   101→    }
   102→
   103→    handleExtractError(isFirstPage);
   104→  } catch {
   105→    handleExtractError(isFirstPage);
   106→  }
   107→}
   108→
   109→function shouldFetchBalance(status: PointsBalanceStatus): boolean {
   110→  return (
   111→    status !== PointsBalanceStatus.LOADING &&
   112→    status !== PointsBalanceStatus.SUCCESS
   113→  );
   114→}
   115→
   116→function handleBalanceSuccess(points?: number): void {
   117→  const { pointsExtractActions } = useRootStore.getState();
   118→  pointsExtractActions.setBalance(points);
   119→  eventServerResponse(ANALYTICS_EVENTS.BALANCE_SUCCESS);
   120→}
   121→
   122→function handleBalanceError(): void {
   123→  const { pointsExtractActions } = useRootStore.getState();
   124→  pointsExtractActions.setBalanceStatus(PointsBalanceStatus.ERROR);
   125→  eventServerResponse(ANALYTICS_EVENTS.BALANCE_ERROR);
   126→}
   127→
   128→export async function getPointsBalance(): Promise<void> {
   129→  const { pointsExtractActions, pointsBalance } = useRootStore.getState();
   130→
   131→  if (!shouldFetchBalance(pointsBalance.status)) {
   132→    return;
   133→  }
   134→
   135→  try {
   136→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.LOADING);
   137→
   138→    const response = await getPointsBalanceApi();
   139→    const returnCode =
   140→      response?.data?.status?.returnCode ??
   141→      response?.data?.status?.codigoRetorno;
   142→    const points = response?.data?.data?.points;
   143→
   144→    if (returnCode === EXTRACT_CONSTANTS.BALANCE_SUCCESS_RETURN_CODE) {
   145→      handleBalanceSuccess(points);
   146→      return;
   147→    }
   148→
   149→    handleBalanceError();
   150→  } catch {
   151→    handleBalanceError();
   152→  }
   153→}
