    28→export const getFormattedPointsValue = (amount: number, type: TransactionType): string => {
    29→  const prefix = (type === 'CREDIT' || type === 'REFUNDED') ? '+ ' : '- ';
    30→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
    31→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
    32→};
    33→
    34→export const getFormattedHighlightText = (date: string, gainType: TransactionGainType, moment: any): string => {
    35→  const transactionDate = moment(date);
    36→  const day = transactionDate.format('DD');
    37→  const month = transactionDate.format('MMM').toLowerCase();
    38→  const year = transactionDate.format('YYYY');
    39→  const time = transactionDate.format('HH:mm');
    40→  
    41→  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
