    58→
    59→export const getMarketplaceTitle = (transaction: MyOrdersDetailProps['transaction']): string | null => {
    60→  if (!transaction?.marketplace?.orders) return null;
    61→
    62→  const allItems: Array<{ name: string }> = [];
    63→  transaction.marketplace.orders.forEach(order => {
    64→    if (order.items) {
    65→      allItems.push(...order.items);
    66→    }
    67→  });
    68→
    69→  if (allItems.length === 0) return null;
    70→  if (allItems.length === 1) return allItems[0].name;
    71→  
    72→  const firstItemName = allItems[0].name;
    73→  const secondItemFirstWord = allItems[1].name.split(' ')[0];
    74→  
    75→  if (allItems.length === 2) {
    76→    return `${firstItemName} e ${secondItemFirstWord}`;
    77→  }
    78→  
    79→  const remainingCount = allItems.length - 2;
    80→  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
    81→};
